@startuml
hide methods
skinparam classAttributeIconSize 0

class "note" as note << (E,#B7D7B7) >> {
  id
  job_id
  text
  created
}

class "job" as job << (E,#B7D7B7) >> {
  id
  status [scheduled|active|invoicing|to priced|completed]
  created
  client_name
  address
  client_contact_number
}

note }o--|| job
@enduml
